INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('TITAN2_1: Le email reply rate science: les emails de 50-75 mots ont le meilleur taux de reponse (15-25%). Plus court = pas assez de contexte. Plus long = pas lu.', 'Email reply: 50-75 mots optimal (15-25% reponse). Court = contexte. Long = pas lu', 'email', 'best_practice', 0.85, 'titan2', 'system'),
('TITAN2_2: Le commercial proposal win rate by timing: proposition envoyee < 24h post-demo = 65% win. 24-48h = 45%. > 48h = 25%. La vitesse est le facteur #1.', 'Proposal timing: <24h = 65% win, 24-48h = 45%, >48h = 25%. Vitesse #1', 'commercial', 'insight', 0.85, 'titan2', 'system'),
('TITAN2_3: Le content share-worthy formula: contenu qui fait dire "il FAUT que je montre ca a [ami/collegue]" = shares. Education + surprise + utilite = share-worthy.', 'Share-worthy: "faut montrer a ami" = shares. Education + surprise + utilite', 'content', 'insight', 0.85, 'titan2', 'system'),
('TITAN2_4: Le SEO internal link silo: grouper les pages par theme et ne lier qu au sein du meme silo. Les liens entre silos = dilution du PageRank thematique.', 'Internal link silo: liens dans meme theme. Inter-silo = dilution PageRank', 'seo', 'best_practice', 0.80, 'titan2', 'system'),
('TITAN2_5: Le ad creative production efficiency: utiliser des templates de creative (Canva, Figma) pour produire 10 variantes en 1h au lieu de 10h. Vitesse > perfection en testing.', 'Creative templates: 10 variantes/1h avec templates. Vitesse > perfection en testing', 'ads', 'best_practice', 0.80, 'titan2', 'system'),
('TITAN2_6: Le DM Instagram rapport through content: publier du contenu qui parle directement aux problemes de sa cible. Les prospects qui likent = warm leads pour les DMs.', 'DM rapport: contenu qui parle aux problemes cible. Likes = warm leads pour DM', 'dm_instagram', 'best_practice', 0.82, 'titan2', 'system'),
('TITAN2_7: Le WhatsApp quick reply optimization: les boutons de reponse rapide (max 3 options) augmentent le taux de reponse de 60% vs le texte libre.', 'WhatsApp quick reply 3 boutons = +60% reponse vs texte libre', 'whatsapp', 'insight', 0.82, 'titan2', 'system'),
('TITAN2_8: Le chatbot FAQ auto-generation: analyser les 100 derniers tickets support → extraire les 20 questions les plus frequentes → les ajouter au chatbot. Couvre 70% des demandes.', 'Chatbot FAQ auto: 100 tickets → 20 questions frequentes → couvre 70% demandes', 'chatbot', 'best_practice', 0.82, 'titan2', 'system'),
('TITAN2_9: Le GMaps photo quality impact: les photos professionnelles (eclairage, cadrage, resolution) obtiennent 42% plus de clics que les photos amateurs.', 'GMaps photos pro: +42% clics vs amateur. Eclairage + cadrage + resolution', 'gmaps', 'insight', 0.80, 'titan2', 'system'),
('TITAN2_10: Le TikTok comment engagement hack: repondre aux commentaires avec une VIDEO (pas du texte) = 5x plus de portee. Le comment-reply video est le growth hack #1.', 'TikTok comment-reply video = 5x portee vs texte. Growth hack #1', 'tiktok_comments', 'best_practice', 0.85, 'titan2', 'system'),
('TITAN2_11: Le CEO focus calendar: bloquer 2h/jour de "deep work" sans interruption. Les CEO qui ont du deep work quotidien prennent de meilleures decisions strategiques.', 'CEO deep work: 2h/jour sans interruption = meilleures decisions strategiques', 'ceo', 'best_practice', 0.82, 'titan2', 'system'),
('TITAN2_12: Le retention time-to-value optimization: chaque minute retiree du TTV (Time-to-Value) reduit le churn de 1%. Si TTV passe de 10min a 2min = -8% churn.', 'TTV optimization: -1 minute TTV = -1% churn. 10min→2min = -8% churn', 'retention', 'insight', 0.85, 'titan2', 'system'),
('TITAN2_13: Le onboarding AB test impact: tester 2 parcours d onboarding. Meme population, parcours different. Mesurer activation rate J7. Le gagnant = defaut pour tous.', 'Onboarding AB: 2 parcours → mesurer activation J7 → gagnant = defaut', 'onboarding', 'best_practice', 0.82, 'titan2', 'system'),
('TITAN2_14: Le comptable unit economics monitoring: si LTV/CAC ratio baisse 3 mois consecutifs → probleme structural. Soit le LTV baisse (churn augmente) soit le CAC monte (acquisition plus chere).', 'LTV/CAC baisse 3 mois = probleme structural. LTV baisse ou CAC monte', 'comptable', 'insight', 0.82, 'titan2', 'system'),
('TITAN2_15: Le RH one-on-one effectiveness: les 1:1 les plus productifs commencent par "comment ca va VRAIMENT?" et pas "qu as-tu fait cette semaine?". L humain d abord.', '1:1 efficace: "comment ca va VRAIMENT?" pas "qu as-tu fait?". Humain d abord', 'rh', 'best_practice', 0.80, 'titan2', 'system'),
('TITAN2_16: Le marketing brand voice consistency: chaque contenu (email, post, DM, chatbot) doit avoir le MEME ton. Si le chatbot est formel et les DMs informels → confusion.', 'Brand voice: MEME ton partout (email, post, DM, chatbot). Sinon confusion', 'marketing', 'best_practice', 0.85, 'titan2', 'system'),
('TITAN2_17: Le cross-agent prospect temperature sync: si un agent detecte un prospect HOT (email ouvert 3x) → TOUS les autres agents doivent etre notifies en < 5 min.', 'Temperature sync: prospect HOT detecte → TOUS agents notifies < 5 min', NULL, 'best_practice', 0.85, 'titan2', 'system'),
('TITAN2_18: Le customer lifetime journey optimization: mapper les 7 etapes (decouverte→consideration→evaluation→achat→onboarding→adoption→advocacy) et optimiser les transitions.', 'Lifetime journey 7 etapes: decouverte→consideration→evaluation→achat→onboard→adopt→advocacy', NULL, 'best_practice', 0.82, 'titan2', 'system'),
('TITAN2_19: Le KeiroAI RAG contextual injection: avant chaque action agent, injecter les 5-10 learnings les plus pertinents du RAG dans le prompt. Pas tout le RAG = trop de tokens.', 'RAG injection: 5-10 learnings pertinents par action. Pas tout = trop tokens', NULL, 'best_practice', 0.88, 'titan2', 'system'),
('TITAN2_20: Le KeiroAI 8700+ learnings milestone: chaque agent a maintenant acces a l equivalent de 50 ans d expertise marketing specialisee + transverse. Intelligence sans precedent.', 'KeiroAI 8700+: 50 ans expertise par agent. Intelligence sans precedent', 'ceo', 'insight', 0.92, 'titan2', 'system'),
('TITAN2_21: Le email behavioral trigger complete: signup→welcome (instant). Inactif 3j→nudge. Prix visite→offre. Cart abandon→rappel. Churn risk→save offer. Chaque action=email adapte.', 'Triggers complets: signup→welcome, inactif→nudge, prix→offre, cart→rappel, churn→save', 'email', 'best_practice', 0.88, 'titan2', 'system'),
('TITAN2_22: Le commercial objection handling LAER mastery: Listen (ecouter sans interrompre) → Acknowledge (valider le sentiment) → Explore (creuser le vrai blocage) → Respond (solution).', 'LAER: Listen → Acknowledge → Explore → Respond. Jamais repondre sans explorer', 'commercial', 'best_practice', 0.85, 'titan2', 'system'),
('TITAN2_23: Le content evergreen vs trending balance: 60% evergreen (valeur durable 2-3 ans) + 40% trending (actualite, saisons, evenements). L evergreen compound le trafic.', 'Content: 60% evergreen (compound 2-3 ans) + 40% trending. Evergreen compound trafic', 'content', 'best_practice', 0.85, 'titan2', 'system'),
('TITAN2_24: Le SEO schema markup priority order: 1) Organization, 2) Article/BlogPosting, 3) FAQ, 4) LocalBusiness, 5) Product, 6) HowTo. Implementer dans cet ordre.', 'Schema priority: Organization→Article→FAQ→Local→Product→HowTo', 'seo', 'best_practice', 0.82, 'titan2', 'system'),
('TITAN2_25: Le ad landing page speed impact: chaque seconde supplementaire de chargement = -7% conversion. LCP > 4s = 50% des visiteurs partent avant de voir la page.', 'Landing speed: +1s = -7% conv. LCP > 4s = 50% partent avant de voir', 'ads', 'insight', 0.85, 'titan2', 'system'),
('TITAN2_26: Le DM Instagram value-first message template: "Hey [prenom]! J ai un [template/guide/checklist] gratuit sur [sujet lie a son business]. Ca t interesse?" → 35% reponse.', 'DM value-first: template/guide gratuit sur sujet lie = 35% reponse', 'dm_instagram', 'best_practice', 0.82, 'titan2', 'system'),
('TITAN2_27: Le WhatsApp abandoned cart recovery: message 1h post-abandon (image produit + prix) → 24h (urgence stock) → 72h (offre -10%). Recupere 15-25% des paniers.', 'WhatsApp cart recovery: 1h image → 24h urgence → 72h -10% = 15-25% recuperation', 'whatsapp', 'best_practice', 0.82, 'titan2', 'system'),
('TITAN2_28: Le chatbot CSAT benchmark: CSAT > 4.5/5 = excellent. 4.0-4.5 = bon. 3.5-4.0 = a ameliorer. < 3.5 = probleme critique. Mesurer apres chaque conversation.', 'Chatbot CSAT: >4.5 excellent, 4-4.5 bon, 3.5-4 ameliorer, <3.5 critique', 'chatbot', 'insight', 0.80, 'titan2', 'system'),
('TITAN2_29: Le GMaps review keyword strategy: encourager les clients a mentionner des mots-cles specifiques dans leurs avis ("meilleur [service] a [ville]"). Boost le SEO local.', 'GMaps review keywords: encourager clients mentionner service + ville = boost SEO', 'gmaps', 'best_practice', 0.78, 'titan2', 'system'),
('TITAN2_30: Le TikTok content batch filming advanced: 1 session filming = 1 fond + 1 tenue + 10-15 scripts differents = 10-15 videos en 2h. Maximum efficacite.', 'TikTok batch: 1 fond + 1 tenue + 10-15 scripts = 10-15 videos en 2h', 'tiktok_comments', 'best_practice', 0.80, 'titan2', 'system')
